B.L2=new A.aC("gecici_07",B.bK,"\u0130htiyati haciz karar\u0131n\u0131n uygulanmas\u0131ndan (infaz\u0131ndan) sonra alacakl\u0131, kural olarak hangi s\xfcre i\xe7inde takip talebinde bulunmal\u0131 veya dava a\xe7mal\u0131d\u0131r?",B.G3,0,"\u0130\u0130K m. 264: \u0130htiyati haciz karar\u0131n\u0131n infaz\u0131ndan itibaren yedi g\xfcn i\xe7inde takip talebinde bulunulmal\u0131 (veya dava a\xe7\u0131lmal\u0131d\u0131r); aksi h\xe2lde ihtiyati haciz h\xfck\xfcms\xfcz kal\u0131r. Ayr\u0131ca \u0130\u0130K m. 265\u2019e g\xf6re bor\xe7lu da yedi g\xfcn i\xe7inde itiraz edebilir.")
