B.L9=new A.aC("kanun_03",B.bM,"Temyiz ba\u015fvuru s\xfcresi kural olarak ne kadard\u0131r?",B.Fu,1,"HMK m. 361: Temyiz s\xfcresi, BAM karar\u0131n\u0131n tebli\u011finden itibaren iki haftad\u0131r.")
B.Fo=s(["Bu s\u0131n\u0131r\u0131n alt\u0131ndaki kararlar kesindir; istinafa g\xf6t\xfcr\xfclemez.","Bu s\u0131n\u0131r\u0131n alt\u0131ndaki kararlar do\u011frudan Yarg\u0131tay\u2019da temyiz edilir.","S\u0131n\u0131r yaln\u0131zca ceza davalar\u0131nda uygulan\u0131r.","S\u0131n\u0131r\u0131n \xfczerindeki kararlar kesindir."],t.s)
B.Lq=new A.aC("kanun_04",B.bM,'Malvarl\u0131\u011f\u0131na ili\u015fkin davalarda istinaf "kesinlik s\u0131n\u0131r\u0131" ne anlama gelir?',B.Fo,0,"HMK m. 341: Miktar veya de\u011feri belirli bir tutar\u0131 ge\xe7meyen malvarl\u0131\u011f\u0131 davalar\u0131na ili\u015fkin kararlar kesindir (istinaf edilemez). Bu s\u0131n\u0131r her y\u0131l yeniden de\u011ferleme oran\u0131nda artar; g\xfcncel tutar\u0131 teyit et.")
B.Fr=s(["Kesinlik s\u0131n\u0131r\u0131n\u0131n alt\u0131nda kal\u0131rsa istinafa g\xf6t\xfcr\xfclemez.","Miktar\u0131na bak\u0131lmaks\u0131z\u0131n istinaf yolu a\xe7\u0131kt\u0131r.","Manevi tazminat kararlar\u0131 hi\xe7bir \u015fekilde istinaf edilemez.","Yaln\u0131zca davac\u0131 istinafa ba\u015fvurabilir."],t.s)
B.Lm=new A.aC("kanun_05",B.bM,"Manevi tazminat davalar\u0131nda verilen kararlar bak\u0131m\u0131ndan istinaf yolu nas\u0131ld\u0131r?",B.Fr,1,"Manevi tazminat davalar\u0131nda dava de\u011feri/h\xfckmedilen miktar d\xfc\u015f\xfck olsa dahi, miktar g\xf6zetilmeksizin istinaf yolu a\xe7\u0131k kabul edilir (kesinlik s\u0131n\u0131r\u0131 manevi tazminat istemine uygulanmaz).")
B.FF=s(["Karar ge\xe7ersiz olur.","Karar \u015fekl\xee/maddi anlamda kesinle\u015fir ve icra edilebilir h\xe2le gelir.","Dava yeniden ilk derece mahkemesinde g\xf6r\xfcl\xfcr.","Karar resen Yarg\u0131tay\u2019a g\xf6nderilir."],t.s)
B.Lp=new A.aC("kanun_06",B.bM,"S\xfcresinde kanun yoluna ba\u015fvurulmayan bir karar bak\u0131m\u0131ndan sonu\xe7 nedir?",B.FF,1,"Kanun yolu s\xfcresi i\xe7inde ba\u015fvurulmazsa veya kanun yolu kapal\u0131ysa karar kesinle\u015fir; kesinle\u015fen karar icra edilebilir ve kesin h\xfck\xfcm (res judicata) etkisi do\u011furur.")
B.Fv=s(["BAM\u2019\u0131n t\xfcm kararlar\u0131 istisnas\u0131z temyiz edilebilir.","Kanunda say\u0131lan baz\u0131 kararlar (\xf6r. temyiz kesinlik s\u0131n\u0131r\u0131n\u0131n alt\u0131nda kalanlar) temyiz edilemez.","BAM kararlar\u0131 yaln\u0131zca Anayasa Mahkemesi\u2019nde incelenir.","BAM kararlar\u0131 hi\xe7bir \u015fekilde temyiz edilemez."],t.s)
B.KV=new A.aC("kanun_07",B.bM,"B\xf6lge adliye mahkemesi kararlar\u0131n\u0131n temyiz edilebilirli\u011fi bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi do\u011frudur?",B.Fv,1,"HMK m. 362: Miktar/de\u011feri belirli s\u0131n\u0131r\u0131 ge\xe7meyen davalara ili\u015fkin kararlar ile maddede say\u0131lan di\u011fer kararlar temyiz edilemez (kesindir). Bu s\u0131n\u0131r da y\u0131ll\u0131k olarak yeniden de\u011ferleme oran\u0131nda artar.")
