B.cU=new A.lf("Alternatif Uyu\u015fmazl\u0131k \xc7\xf6z\xfcmleri",B.Ba,4,"arabuluculuk")
B.FV=s(["Tamamen ihtiyaridir, hi\xe7bir zorunluluk yoktur.","Arabulucuya ba\u015fvurulmu\u015f olmas\u0131 bir dava \u015fart\u0131d\u0131r.","Yaln\u0131zca taraflar isterse uygulan\u0131r ve dava a\xe7maya engel de\u011fildir.","Sadece toplu i\u015f uyu\u015fmazl\u0131klar\u0131nda zorunludur."],t.s)
B.KQ=new A.aC("arabulucu_01",B.cU,"\u0130\u015f\xe7i-i\u015fveren aras\u0131ndaki kanuna/s\xf6zle\u015fmeye dayanan i\u015f\xe7ilik alaca\u011f\u0131 ve i\u015fe iade davalar\u0131nda arabuluculu\u011fun rol\xfc nedir?",B.FV,1,"7036 say\u0131l\u0131 \u0130\u015f Mahkemeleri Kanunu m. 3: Kanuna, bireysel veya toplu i\u015f s\xf6zle\u015fmesine dayanan i\u015f\xe7i/i\u015fveren alaca\u011f\u0131, tazminat\u0131 ve i\u015fe iade taleplerinde arabulucuya ba\u015fvurulmu\u015f olmas\u0131 dava \u015fart\u0131d\u0131r.")
B.FK=s(["T\xfcm ticari davalar\u0131 istisnas\u0131z kapsar.","Konusu bir miktar paran\u0131n \xf6denmesi olan alacak ve tazminat taleplerini kapsar.","Yaln\u0131zca \u015firketler hukukundan do\u011fan davalar\u0131 kapsar.","Yaln\u0131zca kambiyo senetlerine ili\u015fkin davalar\u0131 kapsar."],t.s)
B.L1=new A.aC("arabulucu_02",B.cU,"Ticari davalarda dava \u015fart\u0131 olan arabuluculuk hangi t\xfcr talepleri kapsar?",B.FK,1,"TTK m. 5/A: Konusu bir miktar paran\u0131n \xf6denmesi olan alacak ve tazminat talepleri hakk\u0131nda ticari davalarda, dava a\xe7\u0131lmadan \xf6nce arabulucuya ba\u015fvurulmu\u015f olmas\u0131 dava \u015fart\u0131d\u0131r.")
B.GO=s(["Do\u011frudan davay\u0131 esastan reddeder.","Davac\u0131ya, son tutana\u011f\u0131n bir haftal\u0131k kesin s\xfcre i\xe7inde sunulmas\u0131 i\xe7in ihtarda bulunur; sunulmazsa dava usulden reddedilir.","Tutana\u011f\u0131 resen arabuluculuk b\xfcrosundan ister.","Davay\u0131 hi\xe7bir uyar\u0131 yapmadan g\xf6revsizlikle reddeder."],t.s)
B.L6=new A.aC("arabulucu_04",B.cU,"Arabuluculuk dava \u015fart\u0131 olan bir davada, anla\u015fmaya var\u0131lamad\u0131\u011f\u0131na ili\u015fkin son tutanak dava dilek\xe7esine eklenmemi\u015fse mahkeme \xf6nce ne yapar?",B.GO,1,"7036 m. 3/2: Arabulucuya ba\u015fvurulmu\u015f ancak son tutanak eklenmemi\u015fse, mahkeme davac\u0131ya bir haftal\u0131k kesin s\xfcre verir; bu s\xfcre i\xe7inde sunulmazsa dava dilek\xe7esi kar\u015f\u0131 tarafa tebli\u011fe \xe7\u0131kar\u0131lmadan dava usulden reddedilir. (Hi\xe7 ba\u015fvurulmam\u0131\u015fsa s\xfcre verilmeden do\u011frudan reddedilir.)")
B.H1=s(["K\u0131dem tazminat\u0131 talebi","Fazla mesai \xfccreti alaca\u011f\u0131","\u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131","\u0130hbar tazminat\u0131 talebi"],t.s)
B.KZ=new A.aC("arabulucu_05",B.cU,"A\u015fa\u011f\u0131dakilerden hangisi i\u015f hukukunda dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 DI\u015eINDADIR?",B.H1,2,"7036 m. 3: \u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131 ile bunlarla ilgili tespit, itiraz ve r\xfccu davalar\u0131 dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 d\u0131\u015f\u0131ndad\u0131r.")
B.GC=s(["\xdc\xe7 hafta i\xe7inde; zorunlu h\xe2llerde en fazla bir hafta uzat\u0131labilir.","\u0130ki ay i\xe7inde; uzatma m\xfcmk\xfcn de\u011fildir.","Bir y\u0131l i\xe7inde.","S\xfcre \xf6ng\xf6r\xfclmemi\u015ftir."],t.s)
B.Ll=new A.aC("arabulucu_06",B.cU,"Dava \u015fart\u0131 arabuluculukta arabulucu, ba\u015fvuru tarihinden itibaren s\xfcreci kural olarak ne kadar s\xfcrede tamamlamal\u0131d\u0131r?",B.GC,0,"\u0130\u015f ve ticari uyu\u015fmazl\u0131klarda arabulucu, g\xf6revlendirildi\u011fi tarihten itibaren s\xfcreci \xfc\xe7 hafta i\xe7inde sonu\xe7land\u0131r\u0131r; bu s\xfcre zorunlu h\xe2llerde arabulucu taraf\u0131ndan en fazla bir hafta uzat\u0131labilir.")
B.ES=s(["Tan\u0131k","Senet","Yemin","Bilirki\u015fi"],t.s)
B.L4=new A.aC("ispat_11",B.b9,"Hukuki i\u015flemlerin miktar veya de\u011feri kanunda \xf6ng\xf6r\xfclen s\u0131n\u0131r\u0131 ge\xe7ti\u011fi takdirde kural olarak hangi delille ispat edilmesi zorunludur?",B.ES,1,"HMK m. 200 uyar\u0131nca, bir hakk\u0131n do\u011fumu, d\xfc\u015f\xfcr\xfclmesi, devri, de\u011fi\u015ftirilmesi, yenilenmesi, ertelenmesi, ikrar\u0131 ve itfas\u0131 amac\u0131yla yap\u0131lan hukuki i\u015flemlerin, yap\u0131ld\u0131klar\u0131 zamanki miktar veya de\u011ferleri kanunda \xf6ng\xf6r\xfclen s\u0131n\u0131r\u0131 ge\xe7ti\u011fi takdirde kural olarak senetle ispatlanmas\u0131 zorunludur.")
B.Ew=s(["Karde\u015fler aras\u0131ndaki hukuki i\u015flemler","E\u015fler aras\u0131ndaki hukuki i\u015flemler","Ortaklar aras\u0131ndaki ticari i\u015flemler","Altsoy ile \xfcstsoy aras\u0131ndaki hukuki i\u015flemler"],t.s)
B.Ln=new A.aC("ispat_12",B.b9,"A\u015fa\u011f\u0131dakilerden hangisi, senetle ispat zorunlulu\u011fu olan bir hukuki i\u015flemin miktar ne olursa olsun tan\u0131kla ispat edilebilece\u011fi istisnai hallerden (delil ba\u015flang\u0131c\u0131 aranmaks\u0131z\u0131n) biri de\u011fildir?",B.Ew,2,"HMK m. 203 uyar\u0131nca altsoy-\xfcstsoy, karde\u015fler ve e\u015fler aras\u0131ndaki i\u015flemlerde miktar ne olursa olsun tan\u0131k dinlenebilir. Ortaklar aras\u0131ndaki i\u015flemler kural olarak bu istisnaya dahil edilmemi\u015ftir.")
B.iK=s(["1 hafta","2 hafta","3 hafta","4 hafta"],t.s)
B.KO=new A.aC("ispat_13",B.b9,"Taraflar, bilirki\u015fi raporunun kendilerine tebli\u011f tarihinden itibaren kural olarak ka\xe7 hafta i\xe7inde raporda eksik g\xf6rd\xfckleri hususlar\u0131n bilirki\u015fiye tamamlatt\u0131r\u0131lmas\u0131n\u0131 mahkemeden isteyebilirler?",B.iK,1,"HMK m. 281/1 uyar\u0131nca taraflar, bilirki\u015fi raporunun tebli\u011fi tarihinden itibaren iki hafta i\xe7inde raporda eksik veya belirsiz g\xf6rd\xfckleri hususlar\u0131n giderilmesini yahut yeni bir bilirki\u015fi atanmas\u0131n\u0131 isteyebilirler.")
B.L0=new A.aC("gecici_08",B.bK,"Kar\u015f\u0131 taraf dinlenmeden (yoklu\u011funda) verilen ihtiyati tedbir kararlar\u0131na kar\u015f\u0131, itiraz hakk\u0131 olanlar karar\u0131n uygulanmas\u0131 s\u0131ras\u0131nda haz\u0131r bulunmuyorlarsa, tedbirin uygulanmas\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren en ge\xe7 ne kadar s\xfcre i\xe7inde itiraz edebilirler?",B.iK,0,"HMK m. 394/2 uyar\u0131nca kar\u015f\u0131 taraf dinlenmeden verilmi\u015f olan ihtiyati tedbir kararlar\u0131na itiraz s\xfcresi, karar\u0131n uyguland\u0131\u011f\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren bir haftad\u0131r.")
B.G0=s(["\u0130htiyati tedbir","\u0130htiyati haciz","Delil tespiti","\u0130htiyari dava arkada\u015fl\u0131\u011f\u0131"],t.s)
B.Le=new A.aC("gecici_09",B.bK,"G\xf6r\xfclmekte olan veya ileride a\xe7\u0131lacak bir davada ispat vas\u0131tas\u0131 olarak kullan\u0131lacak olan delillerin kaybolmas\u0131 veya g\xf6sterilmesinin \xe7ok zorla\u015fmas\u0131 ihtimali kar\u015f\u0131s\u0131nda ba\u015fvurulan ge\xe7ici hukuki koruma kurumu a\u015fa\u011f\u0131dakilerden hangisidir?",B.G0,2,"HMK m. 400 uyar\u0131nca, taraflar hen\xfcz inceleme s\u0131ras\u0131 gelmemi\u015f olan veya ileride a\xe7\u0131lacak davada ileri s\xfcr\xfclecek delillerin kaybolaca\u011f\u0131 veya ileri s\xfcr\xfclmesinin zorla\u015faca\u011f\u0131 ihtimali varsa delil tespiti isteyebilir.")
B.L3=new A.aC("kanun_08",B.bM,"Hukuk mahkemeleri taraf\u0131ndan verilen nihai kararlara kar\u015f\u0131, karar\u0131n usul\xfcne uygun tebli\u011finden itibaren kural olarak ka\xe7 hafta i\xe7inde istinaf yoluna ba\u015fvurulabilir?",B.iK,1,"HMK m. 345 uyar\u0131nca istinaf yoluna ba\u015fvuru s\xfcresi, karar\u0131n usul\xfcne uygun olarak taraflara tebli\u011finden itibaren iki haftad\u0131r.")
B.GN=s(["Miktar veya de\u011feri temyiz s\u0131n\u0131r\u0131n\u0131 a\u015fan alacak davalar\u0131","Soyba\u011f\u0131na ili\u015fkin kararlar","\xc7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen kararlar","Ta\u015f\u0131nmaz \xfczerindeki ayni haklara ili\u015fkin kararlar"],t.s)
B.Li=new A.aC("kanun_09",B.bM,"B\xf6lge adliye mahkemesi hukuk dairelerinden verilen a\u015fa\u011f\u0131daki kararlardan hangisine kar\u015f\u0131 kural olarak temyiz yoluna ba\u015fvurulamaz?",B.GN,2,"HMK m. 362/1-\xe7 bendine g\xf6re \xe7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen b\xf6lge adliye mahkemesi kararlar\u0131 kesin olup bu kararlara kar\u015f\u0131 temyiz yoluna ba\u015fvurulamaz.")
B.G5=s(["Feragat, h\xfck\xfcm kesinle\u015finceye kadar her zaman yap\u0131labilir.","Feragatin ge\xe7erlili\u011fi kar\u015f\u0131 taraf\u0131n veya mahkemenin kabul\xfcne ba\u011fl\u0131d\u0131r.","Feragat, kesin h\xfck\xfcm gibi hukuki sonu\xe7 do\u011furur.","\u015earta ba\u011fl\u0131 feragat kural olarak ge\xe7erli de\u011fildir."],t.s)
B.KU=new A.aC("taraf_08",B.bL,'Davac\u0131n\u0131n talep sonucundan k\u0131smen veya tamamen vazge\xe7mesi olan "feragat" kurumu ile ilgili a\u015fa\u011f\u0131dakilerden hangisi yanl\u0131\u015ft\u0131r?',B.G5,1,"HMK m. 309 uyar\u0131nca feragat ve kabul, kar\u015f\u0131 taraf\u0131n veya mahkemenin muvafakatine ba\u011fl\u0131 de\u011fildir; tek tarafl\u0131 irade beyan\u0131yla derhal sonu\xe7 do\u011furur.")
