B.Eo=s(["Sadece taraflar\u0131n\u0131n","Sadece dava sebeplerinin","Taraflar\u0131n\u0131n, dava sebeplerinin ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun","Sadece mahkemelerinin"],t.s)
B.Lr=new A.aC("hukum_01",B.KN,"Bir davada verilen karar\u0131n ba\u015fka bir davada maddi anlamda kesin h\xfck\xfcm te\u015fkil edebilmesi i\xe7in her iki davan\u0131n hangi unsurlar\u0131n\u0131n ayn\u0131 olmas\u0131 zorunludur?",B.Eo,2,"HMK m. 303/1 uyar\u0131nca maddi anlamda kesin h\xfck\xfcmden s\xf6z edilebilmesi i\xe7in her iki davan\u0131n taraflar\u0131n\u0131n, dava sebeplerinin (vak\u0131alar\u0131n) ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun ayn\u0131 olmas\u0131 gerekir.")
B.Er=s(["Eksikli\u011fi gidermesi i\xe7in davac\u0131ya bir haftal\u0131k kesin s\xfcre verir.","Davay\u0131 esastan reddeder.","Davay\u0131, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddeder.","Davay\u0131 durdurur ve taraflar\u0131 arabulucuya g\xf6nderir."],t.s)
B.KR=new A.aC("arabulucu_07",B.cU,"Kanunlarda arabuluculu\u011fa ba\u015fvurulmu\u015f olmas\u0131n\u0131n dava \u015fart\u0131 olarak \xf6ng\xf6r\xfcld\xfc\u011f\xfc durumlarda, davac\u0131 arabulucuya ba\u015fvurmadan do\u011frudan dava a\xe7arsa mahkeme nas\u0131l bir karar verir?",B.Er,2,"6325 say\u0131l\u0131 Hukuk Uyu\u015fmazl\u0131klar\u0131nda Arabuluculuk Kanunu m. 18/A-2 uyar\u0131nca, arabulucuya ba\u015fvurulmadan dava a\xe7\u0131ld\u0131\u011f\u0131n\u0131n anla\u015f\u0131lmas\u0131 halinde herhangi bir i\u015flem yap\u0131lmaks\u0131z\u0131n davan\u0131n, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddine karar verilir.")
